{
  "name": "MathCheck AI",
  "description": "Scan your math homework (typed or handwritten) and get instant feedback on whether your answers are correct.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MathProblem {
  id: string;
  problemText: string;
  studentAnswer: string;
  isCorrect: boolean;
  correctAnswer: string;
  explanation: string;
}

export interface HomeworkAnalysis {
  problems: MathProblem[];
  summary: string;
  score: string;
}

export enum AppState {
  IDLE = 'IDLE',
  SCANNING = 'SCANNING',
  ANALYZING = 'ANALYZING',
  RESULTS = 'RESULTS'
}

import { GoogleGenAI, Type } from "@google/genai";
import { HomeworkAnalysis } from "../types";

export const analyzeMathHomework = async (base64Image: string): Promise<HomeworkAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: `You are a professional math tutor. Analyze this image of math homework. It may contain typed text or legible student handwriting.

          Your tasks:
          1. Identify each math problem.
          2. Identify the student's written answer for each problem (if any).
          3. Evaluate if the student's answer is mathematically correct.
          4. If incorrect, provide the correct answer and a very brief explanation of why it was wrong or how to solve it.
          5. Provide a summary of the overall work and a score (e.g., "4/5 correct").

          Return the data in the specified JSON format. If no problems are found, return empty lists.`
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          problems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                problemText: { type: Type.STRING },
                studentAnswer: { type: Type.STRING },
                isCorrect: { type: Type.BOOLEAN },
                correctAnswer: { type: Type.STRING },
                explanation: { type: Type.STRING },
              },
              required: ["id", "problemText", "studentAnswer", "isCorrect", "correctAnswer", "explanation"],
            },
          },
          summary: { type: Type.STRING },
          score: { type: Type.STRING },
        },
        required: ["problems", "summary", "score"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as HomeworkAnalysis;
};

import React from 'react';
import { MathProblem } from '../types';

interface ProblemCardProps {
  problem: MathProblem;
}

const ProblemCard: React.FC<ProblemCardProps> = ({ problem }) => {
  return (
    <div className={`p-5 rounded-2xl border-2 mb-4 transition-all ${
      problem.isCorrect 
        ? 'border-green-100 bg-green-50 shadow-sm' 
        : 'border-red-100 bg-red-50 shadow-sm'
    }`}>
      <div className="flex items-start justify-between mb-2">
        <h3 className="font-semibold text-slate-800 text-lg">Problem: {problem.problemText}</h3>
        {problem.isCorrect ? (
          <span className="flex items-center bg-green-200 text-green-800 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">
            Correct
          </span>
        ) : (
          <span className="flex items-center bg-red-200 text-red-800 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider">
            Incorrect
          </span>
        )}
      </div>

      <div className="space-y-2 text-sm md:text-base">
        <div className="flex gap-2">
          <span className="font-medium text-slate-500">Your Answer:</span>
          <span className="text-slate-900 font-bold">{problem.studentAnswer}</span>
        </div>

        {!problem.isCorrect && (
          <>
            <div className="flex gap-2">
              <span className="font-medium text-slate-500">Correct Answer:</span>
              <span className="text-green-700 font-bold">{problem.correctAnswer}</span>
            </div>
            <div className="mt-2 p-3 bg-white/50 rounded-lg text-slate-700 italic border border-red-100">
              {problem.explanation}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default ProblemCard;

import React, { useState, useRef, useCallback } from 'react';
import { AppState, HomeworkAnalysis } from './types';
import { analyzeMathHomework } from './services/geminiService';
import ProblemCard from './components/ProblemCard';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.IDLE);
