            </div>
          </div>
        )}

        {/* Hidden File Input */}
        <input
          type="file"
          ref={fileInputRef}
          className="hidden"
          accept="image/*"
          capture="environment"
          onChange={handleCapture}
        />
      </main>

      {/* Persistent CTA at bottom on results */}
      {state === AppState.RESULTS && (
        <div className="fixed bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-50 to-transparent flex justify-center">
          <button 
            onClick={reset}
            className="w-full max-w-xs bg-white border-2 border-indigo-600 text-indigo-600 font-bold py-4 rounded-2xl shadow-lg active:scale-95 transition-all"
          >
            Scan Another Page
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

