        <h3 className="font-semibold text-slate-800 dark:text-slate-100 text-lg">Problem: {problem.problemText}</h3>
        {problem.isCorrect ? (
          <span className="flex items-center bg-green-200 dark:bg-green-800 text-xl px-3 py-1 rounded-full shadow-sm" aria-label="Correct">
            👍
          </span>
        ) : (
          <span className="flex items-center bg-red-200 dark:bg-red-800 text-xl px-3 py-1 rounded-full shadow-sm" aria-label="Incorrect">
            👎
          </span>
        )}
      </div>

      <div className="space-y-2 text-sm md:text-base">
        <div className="flex gap-2">
          <span className="font-medium text-slate-500 dark:text-slate-400">Your Answer:</span>
          <span className="text-slate-900 dark:text-white font-bold">{problem.studentAnswer}</span>
        </div>

        {!problem.isCorrect && (
          <>
