          />
        )}

        {state === AppState.SCANNING && (
          <CameraView 
            onCapture={onCameraCapture} 
            onCancel={() => setState(AppState.IDLE)} 
          />
        )}

        {state === AppState.ANALYZING && (
          <div className="flex flex-col items-center justify-center h-[70vh] space-y-6">
            <div className="relative w-48 h-64 rounded-2xl overflow-hidden shadow-2xl border-4 border-white dark:border-slate-700 bg-slate-200 dark:bg-slate-800">
              {capturedImage && (
                <img src={capturedImage} alt="Scanning" className="w-full h-full object-cover" />
              )}
              <div className="absolute inset-0 bg-indigo-600/20 flex items-center justify-center">
                 <div className="w-full h-1 bg-white/80 absolute top-0 animate-[scan_2s_ease-in-out_infinite]"></div>
              </div>
            </div>
            <style>{`
              @keyframes scan {
                0% { top: 0; }
                50% { top: 100%; }
                100% { top: 0; }
              }
            `}</style>
            <div className="text-center space-y-2">
              <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">Analyzing Homework...</h3>
              <p className="text-slate-500 dark:text-slate-400">Tailoring feedback for {profile.gradeLevel}.</p>
            </div>
          </div>
        )}

        {state === AppState.RESULTS && results && (
          <div className="space-y-6 pb-24 animate-in slide-in-from-bottom-4 duration-500">
            <div className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-wider">Overall Score</p>
                  <h3 className="text-4xl font-black text-indigo-600 dark:text-indigo-400">{results.score}</h3>
                </div>
                <div className="max-w-[60%] text-right">
                  <p className="text-slate-600 dark:text-slate-300 text-sm italic">{results.summary}</p>
                </div>
              </div>

              {results.handwritingLegibilityFeedback && (
                <div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-100 dark:border-amber-900/40 p-4 rounded-2xl flex gap-3 items-start">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-amber-600 dark:text-amber-500 mt-0.5 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                  </svg>
                  <div>
                    <p className="text-xs font-bold text-amber-800 dark:text-amber-400 uppercase tracking-tight">Handwriting Legibility</p>
                    <p className="text-sm text-amber-900 dark:text-amber-200">{results.handwritingLegibilityFeedback}</p>
                  </div>
                </div>
              )}
            </div>

            <div className="space-y-4">
              <h4 className="text-lg font-bold text-slate-800 dark:text-slate-100 ml-1">Problem Details</h4>
              {results.problems.map((problem) => (
                <ProblemCard key={problem.id} problem={problem} />
              ))}
            </div>
          </div>
        )}

        <input
          type="file"
          ref={fileInputRef}
          className="hidden"
          accept="image/*"
          onChange={handleCapture}
        />
      </main>

      {state === AppState.RESULTS && (
        <div className="fixed bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-50 dark:from-slate-900 to-transparent flex justify-center z-10">
          <button 
            onClick={reset}
            className="w-full max-w-xs bg-indigo-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-indigo-200 dark:shadow-none active:scale-95 transition-all"
          >
            New Scan
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

export interface MathProblem {
  id: string;
  problemText: string;
  studentAnswer: string;
  isCorrect: boolean;
  correctAnswer: string;
  explanation: string;
  highlightedProblemText?: string;
  highlightedStudentAnswer?: string;
  isUnworked?: boolean;
}

export interface HomeworkAnalysis {
  problems: MathProblem[];
  summary: string;
  score: string;
  handwritingLegibilityFeedback?: string;
  isBlankPage?: boolean;
}

export interface SavedAnalysis extends HomeworkAnalysis {
  savedId: string;
  timestamp: number;
}

export interface UserProfile {
  name: string;
  gradeLevel: string;
}

export enum AppState {
  IDLE = 'IDLE',
  SCANNING = 'SCANNING',
  ANALYZING = 'ANALYZING',
  RESULTS = 'RESULTS',
  SETTINGS = 'SETTINGS'
}

import { GoogleGenAI, Type } from "@google/genai";
import { HomeworkAnalysis, UserProfile } from "../../types";

export const analyzeMathHomework = async (base64Image: string, profile?: UserProfile): Promise<HomeworkAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const studentContext = profile 
    ? `The student is named ${profile.name} and is at a ${profile.gradeLevel} level.` 
    : "The student's grade level is unknown.";

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: `You are a professional math tutor. ${studentContext} Analyze this image of math homework. It may contain typed text or student handwriting.

          Your tasks:
          1. Identify each math problem.
          2. Identify the student's written answer for each problem (if any).
          3. Evaluate if the student's answer is mathematically correct.
          4. If incorrect, provide the correct answer and a very brief explanation tailored to their grade level.
          5. Provide a summary of the overall work and a score (e.g., "4/5 correct").
          6. IMPORTANT: Provide specific feedback on the legibility of the handwriting.
          7. BLANK PAGE DETECTION: If the image appears to be a blank worksheet or a page with NO student handwriting/work/answers at all, set the "isBlankPage" property to true.
          8. UNWORKED PROBLEM DETECTION: If a specific problem has NO student handwriting, work, or answer next to it, set "isUnworked" to true for that problem.

          HIGHLIGHTING ERRORS:
          If the student's answer is incorrect:
          - Create a "highlightedStudentAnswer" where you wrap the specific parts of their answer that are wrong in double equals signs (e.g., "x = ==5==").
          - Create a "highlightedProblemText" where you wrap parts of the original problem that the student likely misread or misapplied in double equals signs (e.g., "Solve for ==y==" if they solved for x).

          Return the data in the specified JSON format. If a problem is unworked, do not score it as incorrect, simply flag it as isUnworked.`
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          problems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                problemText: { type: Type.STRING },
                studentAnswer: { type: Type.STRING },
                isCorrect: { type: Type.BOOLEAN },
                correctAnswer: { type: Type.STRING },
                explanation: { type: Type.STRING },
                highlightedProblemText: { type: Type.STRING },
                highlightedStudentAnswer: { type: Type.STRING },
                isUnworked: { type: Type.BOOLEAN, description: "True if the student has not attempted this problem." }
              },
              required: ["id", "problemText", "studentAnswer", "isCorrect", "correctAnswer", "explanation"],
            },
          },
          summary: { type: Type.STRING },
          score: { type: Type.STRING },
          handwritingLegibilityFeedback: { 
            type: Type.STRING,
            description: "Feedback on how easy it was to read the student's handwriting."
          },
          isBlankPage: { 
            type: Type.BOOLEAN,
            description: "True if the page is blank or has no student work."
          }
        },
        required: ["problems", "summary", "score", "handwritingLegibilityFeedback", "isBlankPage"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as HomeworkAnalysis;
};

import React from 'react';
import { MathProblem } from '../types';

interface ProblemCardProps {
  problem: MathProblem;
}

const ProblemCard: React.FC<ProblemCardProps> = ({ problem }) => {
  // Helper to render text with ==highlighted== sections
  const renderHighlightedText = (text: string | undefined, original: string) => {
    if (!text || !text.includes('==')) return original;

    const parts = text.split(/(==.*?==)/g);
    return parts.map((part, index) => {
      if (part.startsWith('==') && part.endsWith('==')) {
        const content = part.slice(2, -2);
        return (
          <span 
            key={index} 
            className="bg-red-200 dark:bg-red-900/50 text-red-900 dark:text-red-200 px-1 rounded border-b-2 border-red-500 font-bold"
          >
            {content}
          </span>
        );
      }
      return part;
    });
  };

  const getContainerStyles = () => {
    if (problem.isUnworked) {
      return 'border-slate-200 bg-slate-100/50 dark:bg-slate-800/40 dark:border-slate-700 shadow-sm';
    }
    return problem.isCorrect 
      ? 'border-green-100 bg-green-50 dark:bg-green-900/10 dark:border-green-900/30 shadow-sm' 
      : 'border-red-100 bg-red-50 dark:bg-red-900/10 dark:border-red-900/30 shadow-sm';
  };

  const renderStatus = () => {
    if (problem.isUnworked) {
      return (
        <span className="flex items-center bg-slate-200 dark:bg-slate-700 text-xs font-bold text-slate-600 dark:text-slate-300 px-3 py-1 rounded-full shadow-sm ml-2 uppercase tracking-wider">
          Unworked
        </span>
      );
    }
    return problem.isCorrect ? (
      <span className="flex items-center bg-green-200 dark:bg-green-800 text-xl px-3 py-1 rounded-full shadow-sm ml-2" aria-label="Correct">
        👍
      </span>
    ) : (
      <span className="flex items-center bg-red-200 dark:bg-red-800 text-xl px-3 py-1 rounded-full shadow-sm ml-2" aria-label="Incorrect">
        👎
      </span>
    );
  };

  return (
    <div className={`p-5 rounded-2xl border-2 mb-4 transition-all ${getContainerStyles()}`}>
      <div className="flex items-start justify-between mb-3">
        <div className="flex-1">
          <h3 className="font-semibold text-slate-800 dark:text-slate-100 text-lg leading-tight">
            Problem: {renderHighlightedText(problem.highlightedProblemText, problem.problemText)}
          </h3>
        </div>
        {renderStatus()}
      </div>

      <div className="space-y-3 text-sm md:text-base">
        {problem.isUnworked ? (
          <div className="flex items-center gap-2 p-3 bg-white/40 dark:bg-slate-900/40 rounded-xl border border-slate-200 dark:border-slate-700 italic text-slate-600 dark:text-slate-400">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
            </svg>
            <span>Please try this problem first! No handwriting detected.</span>
          </div>
        ) : (
          <>
            <div className="flex items-start gap-2">
              <span className="font-medium text-slate-500 dark:text-slate-400 shrink-0">Your Answer:</span>
              <span className="text-slate-900 dark:text-white font-bold">
                {renderHighlightedText(problem.highlightedStudentAnswer, problem.studentAnswer)}
              </span>
            </div>

            {!problem.isCorrect && (
              <>
                <div className="flex items-start gap-2">
                  <span className="font-medium text-slate-500 dark:text-slate-400 shrink-0">Correct Answer:</span>
                  <span className="text-green-700 dark:text-green-400 font-bold">{problem.correctAnswer}</span>
                </div>
                <div className="mt-3 p-4 bg-white/60 dark:bg-slate-800/60 rounded-xl text-slate-700 dark:text-slate-300 italic border border-red-100 dark:border-red-900/30 shadow-inner">
                  <div className="flex gap-2">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-indigo-500 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    <span>{problem.explanation}</span>
                  </div>
                </div>
              </>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default ProblemCard;
